const crypto = require('crypto');

const webhookBody = $('Webhook CAPI Purchase').first().json.body || $('Webhook CAPI Purchase').first().json;
const config = $('Fetch Brand Config').first().json;

function sha256(value) {
  if (value == null || value === '' || value === 'NULL') return null;
  const normalized = String(value).trim().toLowerCase();
  return crypto.createHash('sha256').update(normalized).digest('hex');
}

function normalizePhone(phone) {
  if (phone == null) return null;
  const digits = String(phone).replace(/\D/g, '');
  // Add country code if missing (Brazil)
  if (digits.length <= 11 && !digits.startsWith('55')) {
    return '55' + digits;
  }
  return digits;
}

const email = webhookBody.email || null;
const phone = webhookBody.phone || null;
const firstName = webhookBody.first_name || webhookBody.fn || null;
const lastName = webhookBody.last_name || webhookBody.ln || null;
const city = webhookBody.city || null;
const state = webhookBody.state || null;
const zipCode = webhookBody.zip_code || null;
const country = webhookBody.country || 'br';

const monetaryValue = webhookBody.monetary_value || webhookBody.value || 0;
const currency = webhookBody.currency || 'BRL';
const opportunityId = webhookBody.opportunity_id || webhookBody.contact_id || null;
const contactId = webhookBody.contact_id || null;
const eventSourceUrl = webhookBody.event_source_url || null;
const clientIpAddress = webhookBody.client_ip_address || null;
const clientUserAgent = webhookBody.client_user_agent || null;
const fbp = webhookBody.fbp || null;
const fbc = webhookBody.fbc || null;

const userData = {};
if (sha256(email)) userData.em = [sha256(email)];
if (sha256(normalizePhone(phone))) userData.ph = [sha256(normalizePhone(phone))];
if (sha256(firstName)) userData.fn = [sha256(firstName)];
if (sha256(lastName)) userData.ln = [sha256(lastName)];
if (sha256(city)) userData.ct = [sha256(city)];
if (sha256(state)) userData.st = [sha256(state)];
if (sha256(zipCode)) userData.zp = [sha256(zipCode)];
if (sha256(country)) userData.country = [sha256(country)];
if (clientIpAddress) userData.client_ip_address = clientIpAddress;
if (clientUserAgent) userData.client_user_agent = clientUserAgent;
if (fbp) userData.fbp = fbp;
if (fbc) userData.fbc = fbc;

const eventId = 'purchase_' + (opportunityId || Date.now()) + '_' + Date.now();

const purchaseEvent = {
  event_name: 'Purchase',
  event_time: Math.floor(Date.now() / 1000),
  event_id: eventId,
  event_source_url: eventSourceUrl,
  action_source: 'crm',
  user_data: userData,
  custom_data: {
    value: Number(monetaryValue),
    currency: currency,
    order_id: opportunityId
  }
};

return [{
  json: {
    dataset_id: config.meta_dataset_id,
    access_token: config.meta_access_token,
    location_id: config.location_id,
    brand_name: config.brand_name,
    event_id: eventId,
    event_payload: {
      data: [purchaseEvent]
    },
    opportunity_id: opportunityId,
    contact_id: contactId,
    monetary_value: monetaryValue,
    currency: currency
  }
}];

